import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const repoRoot = path.resolve(__dirname, "..", "..");
const modulePath = path.join(repoRoot, "scripts", "data", "locales.module.mjs");
const classicPath = path.join(repoRoot, "scripts", "data", "locales.js");

const generatedBanner = [
  "// AUTO-GENERATED FILE.",
  "// Source: scripts/data/locales.module.mjs",
  "// Run: npm run sync:locales",
  "// Do not edit this file directly.",
  "",
].join("\n");

function toClassicSource(moduleSource) {
  const withoutImports = moduleSource
    .split(/\r?\n/)
    .filter((line) => !line.startsWith("import "))
    .join("\n");
  const withoutExports = withoutImports.replace(/^export\s+/gm, "");
  return `${generatedBanner}${withoutExports}

globalThis.NindouLocales = {
  controlModeLabels: roomControlModeLabels,
  ruleModeLabels: roomRuleModeLabels,
  deathModeLabels: roomDeathModeLabels,
  localeText: roomLocaleText,
  roomLocale,
  localizedWeaponLabel,
  localizedControlModeLabel,
  localizedNinjuLabel,
  localizedNinjuTypeLabel,
  roomTeamLabel,
  localizedCountdownText,
  localizedRuleModeLabel,
  localizedDeathModeLabel,
  localizedNinjuFontSize,
};
`;
}

async function main() {
  const moduleSource = await fs.readFile(modulePath, "utf8");
  const classicSource = toClassicSource(moduleSource);
  await fs.writeFile(classicPath, classicSource, "utf8");
}

await main();
